# coding: utf-8
import os
import base64
from typing import TYPE_CHECKING

from rainbow_admin.file import RainbowFile


if TYPE_CHECKING:
    from rainbow_admin.admin import RainbowAdmin


class Template(object):
    def __init__(self, admin: "RainbowAdmin" = None, **kwargs):
        self.id = kwargs.get("id")
        self.name = kwargs.get("name")
        self.description = kwargs.get("description")
        self.admin = admin

    @property
    def info(self):
        return dict(id=self.id, name=self.name, description=self.description)

    @property
    def versions(self):
        """列出模板包的版本列表"""
        return self.admin.api.tpl_versions(self.name)

    def update(self, desc):
        """更新模板包，当前仅支持个更新描述"""
        return self.admin.api.update_template(self.id, self.name, desc)

    def delete(self):
        """删除模板包"""
        return self.admin.api.delete_template(self.name)

    def list_files(self, version_name=""):
        """列出模板包指定版本（留空则表示最新版本 or 草稿）的文件列表"""
        return self.admin.api.tpl_list_files(self.name, version_name)

    def get_file(self, name, version_name="") -> RainbowFile:
        """
        返回指定版本指定文件名的 RainbowFile 对象，
        可对 RainbowFile 使用 .text() 方法来获取文件内容

        :param  name: 指定文件名
        :param  version_name: 版本名
        """
        for item in self.list_files(version_name):
            if item['name'] == name:
                tpl_file = RainbowFile(key=name, value=item['metadata'])
                return tpl_file
        return False

    def download_to(self, path, with_dir=False):
        """
        复用 RainbowFile 的方法，TODO
        """
        raise NotImplementedError

    def set_file(self, name, content):
        """
        新增 / 更新模板文件内容

        :param  name: 文件名
        :param  content: 文件内容字符串
        """
        return self.admin.api.tpl_create_file(self.name, name, content)

    def del_file(self, name):
        return self.admin.api.tpl_delete_file(self.name, name)

    def upload_files(self, local_file):
        """
        打包上传模板文件

        :param  local_file: 打包的本地文件名
        """
        with open(local_file, 'rb') as f:
            content = f.read()
            if isinstance(content, str):
                content = content.encode("utf-8")
            encode = base64.b64encode(content).decode("utf-8")
        return self.admin.api.tpl_upload_files(self.name, os.path.basename(local_file), encode)

    def cancel_change(self):
        """撤销草稿的改动"""
        return self.admin.api.tpl_cancel(self.name)

    def create_version(self, version_name, desc=""):
        """
        生成模板包的新版本

        :param  version_name: 版本名
        :param  desc: 版本描述
        """
        return self.admin.api.tpl_create_version(self.name, version_name, description=desc)

    def get_vars(self, version_name=""):
        """
        识别指定版本所有模板文件中的变量 TODO
        """
        return self.admin.api.tpl_get_vars(self.name, version_name)['data']

    def __str__(self) -> str:
        return f"{self.__class__.__name__}(id={self.id}, name={self.name}), desc={self.description}"

    __repr__ = __str__
